# WRONG: scan the whole list to count each word (O(n^2))
counts = {}
for w in words:
    counts[w] = words.count(w)  # re-scans words every time!

# RIGHT: one pass, accumulate in a dict (O(n))
counts = {}
for w in words:
    counts[w] = counts.get(w, 0) + 1

