from collections import Counter

sample = "the cat sat on the mat the mat was flat".split()
assert word_counts(sample) == dict(Counter(sample))
assert word_counts(sample)["the"] == 3
assert word_counts(sample)["mat"] == 2
assert word_counts(sample)["cat"] == 1
assert word_counts([]) == {}
assert word_counts(["a"]) == {"a": 1}
assert word_counts(["x", "x", "x"]) == {"x": 3}
for case in ([], ["a"], ["a", "b", "a"], sample, list("abracadabra")):
    assert word_counts(case) == dict(Counter(case))
